import { createClient, LiveMap } from "@liveblocks/client";
import { createRoomContext } from "@liveblocks/react";

const client = createClient({
  authEndpoint: "/api/liveblocks-auth",
});

type Presence = Record<string, never>;

type Storage = {
  pixels: LiveMap<string, string>;
};

type UserMeta = {
  id?: string;
  info?: Record<string, never>;
};

type RoomEvent = never;

export const {
  suspense: {
    RoomProvider,
    useStorage,
    useMutation,
  },
} = createRoomContext<Presence, Storage, UserMeta, RoomEvent>(client);

import { Liveblocks } from "@liveblocks/node";
import { NextRequest, NextResponse } from "next/server";

const liveblocks = new Liveblocks({
  secret: process.env.LIVEBLOCKS_SECRET_KEY!,
});

export async function POST(request: NextRequest) {
  const session = liveblocks.prepareSession(`user-${Math.random().toString(36).slice(2)}`, {
    userInfo: {},
  });

  // Allow access to any room
  const { room } = await request.json();
  session.allow(room, session.FULL_ACCESS);

  const { status, body } = await session.authorize();
  return new NextResponse(body, { status });
}

"use client";

import { useRef } from "react";
import { LiveMap } from "@liveblocks/client";
import { RoomProvider, useStorage, useMutation } from "../../liveblocks.config";

const ROOM_ID = `pixel-grid-${process.env.NEXT_PUBLIC_ZEALT_RUN_ID}`;
const GRID_SIZE = 8;

function Grid() {
  const colorPickerRef = useRef<HTMLInputElement>(null);

  const pixels = useStorage((root) => root.pixels);

  const paintPixel = useMutation(({ storage }, row: number, col: number) => {
    const color = colorPickerRef.current?.value ?? "#000000";
    storage.get("pixels").set(`${row},${col}`, color);
  }, []);

  const clearGrid = useMutation(({ storage }) => {
    const map = storage.get("pixels");
    for (const key of Array.from(map.keys())) {
      map.delete(key);
    }
  }, []);

  const cells: React.ReactElement[] = [];
  for (let r = 0; r < GRID_SIZE; r++) {
    for (let c = 0; c < GRID_SIZE; c++) {
      const key = `${r},${c}`;
      const color = pixels?.get(key) ?? "";
      cells.push(
        <button
          key={key}
          data-pixel={key}
          data-color={color}
          onClick={() => paintPixel(r, c)}
          style={{
            backgroundColor: color || "#ffffff",
            width: "48px",
            height: "48px",
            border: "1px solid #ccc",
            cursor: "pointer",
          }}
        />
      );
    }
  }

  return (
    <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: "16px", padding: "24px" }}>
      <h1 style={{ fontSize: "24px", fontWeight: "bold" }}>Collaborative Pixel Grid</h1>
      <div style={{ display: "flex", gap: "12px", alignItems: "center" }}>
        <label htmlFor="pixel-color">Color:</label>
        <input
          id="pixel-color"
          type="color"
          defaultValue="#ff0000"
          ref={colorPickerRef}
        />
        <button
          id="clear-grid"
          onClick={clearGrid}
          style={{
            padding: "8px 16px",
            backgroundColor: "#ef4444",
            color: "white",
            border: "none",
            borderRadius: "4px",
            cursor: "pointer",
          }}
        >
          Clear Grid
        </button>
      </div>
      <div
        id="pixel-grid"
        style={{
          display: "grid",
          gridTemplateColumns: `repeat(${GRID_SIZE}, 48px)`,
          gap: "2px",
          border: "2px solid #374151",
          padding: "4px",
          backgroundColor: "#374151",
        }}
      >
        {cells}
      </div>
    </div>
  );
}

export default function PixelGrid() {
  return (
    <RoomProvider
      id={ROOM_ID}
      initialPresence={{}}
      initialStorage={{ pixels: new LiveMap<string, string>() }}
    >
      <Grid />
    </RoomProvider>
  );
}

import { Suspense } from "react";
import PixelGrid from "./components/PixelGrid";

export default function Home() {
  return (
    <main>
      <Suspense fallback={<div>Loading...</div>}>
        <PixelGrid />
      </Suspense>
    </main>
  );
}

